import React, { useEffect, useState } from "react";
import "../index.css";

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);

  // Load orders from localStorage on page load
  useEffect(() => {
    const storedOrders = JSON.parse(localStorage.getItem("orders")) || [];
    setOrders(storedOrders);
  }, []);

  // Handle cancel order
  const handleCancel = (orderId) => {
    const reason = prompt("Please enter the reason for cancelling this order:");
    if (!reason || reason.trim() === "") {
      alert("Cancellation reason is required!");
      return;
    }

    const updatedOrders = orders.map((order) =>
      order.id === orderId
        ? { ...order, status: "Cancelled", cancelReason: reason, cancelDate: new Date().toLocaleString() }
        : order
    );

    setOrders(updatedOrders);
    localStorage.setItem("orders", JSON.stringify(updatedOrders));
    alert("✅ Order cancelled successfully!");
  };

  return (
    <div className="orders-page">
      <h2 className="orders-title">Your Orders</h2>

      {orders.length === 0 ? (
        <p className="no-orders">No orders found.</p>
      ) : (
        <div className="orders-list">
          {orders
            .slice()
            .reverse() // latest order first
            .map((order) => (
              <div key={order.id} className="order-card">
                <div className="order-header">
                  <span>Order #{order.id}</span>
                  <span
                    className={`order-status ${
                      order.status === "Cancelled" ? "cancelled" : "placed"
                    }`}
                  >
                    {order.status}
                  </span>
                </div>

                <p className="order-date">📅 {order.date}</p>

                <div className="order-items">
                  {order.items.map((item, index) => (
                    <div key={index} className="order-item">
                      <img
                        src={item.image || "https://via.placeholder.com/80"}
                        alt={item.name}
                        className="order-item-img"
                      />
                      <div className="order-item-info">
                        <h4>{item.name}</h4>
                        <p>₹{item.price} × {item.quantity}</p>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="order-summary">
                  <p><strong>Name:</strong> {order.name}</p>
                  <p><strong>Mobile:</strong> {order.mobile}</p>
                  <p><strong>Address:</strong> {order.address}</p>
                  <p><strong>Payment:</strong> {order.payment}</p>
                  <p><strong>Total:</strong> ₹{order.total}</p>
                </div>

                {order.status === "Cancelled" ? (
                  <div className="cancel-info">
                    <p><strong>Cancelled On:</strong> {order.cancelDate}</p>
                    <p><strong>Reason:</strong> {order.cancelReason}</p>
                  </div>
                ) : (
                  <button
                    className="cancel-btn"
                    onClick={() => handleCancel(order.id)}
                  >
                    Cancel Order
                  </button>
                )}
              </div>
            ))}
        </div>
      )}
    </div>
  );
};

export default OrdersPage;
